arguments.task:
Inspect the Oracle job page at the current Chrome session. Chrome is running on ws://localhost:9222.

1. Connect to Chrome and inspect the page state:
```bash
cd /Users/shivam94/job-copilot && node -e "
const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.connectOverCDP('http://localhost:9222');
  const context = browser.contexts()[0];
  const pages = context.pages();
  // Find the Oracle page
  const page = pages.find(p => p.url().includes('oraclecloud')) || pages[pages.length - 1];

  // Get full page content to understand what's shown
  const html = await page.content();

  // Check for sign-in elements
  const signInEls = await page.evaluate(() => {
    const results = {};
    // Sign in button / link
    const signInBtn = document.querySelector('button:contains(\"Sign In\"), a:contains(\"Sign In\"), [data-automation-id*=\"signIn\"], [class*=\"sign-in\"], [class*=\"signIn\"]');
    results.signInButton = signInBtn ? signInBtn.textContent?.trim() || 'found' : null;

    // Apply button
    const applyBtn = document.querySelector('button:contains(\"Apply\"), a:contains(\"Apply\"), [data-automation-id*=\"apply\"]');
    results.applyButton = applyBtn ? applyBtn.textContent?.trim() || 'found' : null;

    // Email or username field
    const emailField = document.querySelector('input[type=\"email\"], input[name*=\"email\"], input[id*=\"email\"], input[type=\"text\"]');
    results.emailField = emailField ? emailField.placeholder || emailField.name || emailField.id || 'found' : null;

    // Password field
    const passField = document.querySelector('input[type=\"password\"]');
    results.passwordField = passField ? 'found' : null;

    // Any form elements
    const forms = document.querySelectorAll('form');
    results.formCount = forms.length;

    // Main heading
    const h1 = document.querySelector('h1');
    results.heading = h1?.textContent?.trim();

    // Check for verification/code input
    const codeField = document.querySelector('input[name*=\"code\"], input[id*=\"code\"], input[placeholder*=\"code\"], input[placeholder*=\"Code\"], input[autocomplete*=\"one-time\"]');
    results.codeField = codeField ? 'found' : null;

    // Check for text like "code", "verification", "verify"
    const bodyText = document.body?.innerText || '';
    results.hasCodeWord = bodyText.includes('code');
    results.hasVerificationWord = bodyText.includes('verification') || bodyText.includes('Verification');

    return results;
  });

  console.log('Sign-in elements:', JSON.stringify(signInEls, null, 2));
  console.log('Page title:', await page.title());
  console.log('Current URL:', page.url());

  // Take fresh screenshot
  await page.screenshot({ path: '/tmp/jc-state.png', fullPage: false });
  console.log('Screenshot saved to /tmp/jc-state.png');

  await browser.close();
})();
"
```

2. Also check if there are any frames or shadow DOMs that might contain the sign-in:

```bash
cd /Users/shivam94/job-copilot && node -e "
const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.connectOverCDP('http://localhost:9222');
  const context = browser.contexts()[0];
  const pages = context.pages();
  const page = pages.find(p => p.url().includes('oraclecloud')) || pages[pages.length - 1];

  const frameInfo = await page.evaluate(() => {
    return {
      frames: document.querySelectorAll('iframe').length,
      shadowRoots: document.querySelectorAll('*').length,
    };
  });

  const childFrames = page.frames();
  console.log('Child frames count:', childFrames.length);
  childFrames.forEach((f, i) => {
    console.log('Frame', i, ':', f.url());
  });

  await browser.close();
})();
"
```

Report: what is currently shown on the page (sign-in screen? job description? apply form?) and what elements are visible.

