Click "Apply Now" on the Oracle job page and see what happens next.

Chrome is running on ws://localhost:9222.

```bash
cd /Users/shivam94/job-copilot && node -e "
const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.connectOverCDP('http://localhost:9222');
  const context = browser.contexts()[0];
  const pages = context.pages();
  const page = pages.find(p => p.url().includes('oraclecloud')) || pages[pages.length-1];

  console.log('Current URL:', page.url());

  // Click Apply Now
  const applyBtn = page.getByRole('button', { name: /apply/i });
  const applyBtnCount = await applyBtn.count();
  console.log('Apply buttons found:', applyBtnCount);

  if (applyBtnCount > 0) {
    await applyBtn.click();
    console.log('Clicked Apply Now');
    // Wait for navigation or new content
    await page.waitForTimeout(5000);
    console.log('New URL:', page.url());
    console.log('New title:', await page.title());
  }

  // Check what's now visible
  const state = await page.evaluate(() => {
    return {
      url: location.href,
      forms: document.querySelectorAll('form').length,
      emailField: !!document.querySelector('input[type=\"email\"], input[name*=\"email\"], input[id*=\"email\"]'),
      passField: !!document.querySelector('input[type=\"password\"]'),
      codeField: !!document.querySelector('input[name*=\"code\"], input[id*=\"code\"], input[placeholder*=\"code\"], input[autocomplete*=\"one-time\"]'),
      signInBtn: !!document.querySelector('button:contains(\"Sign In\")'),
      bodySnippet: document.body?.innerText?.substring(0, 2000),
      forms_: Array.from(document.querySelectorAll('form')).map(f => ({ id: f.id, action: f.action })),
    };
  });

  console.log('State:', JSON.stringify(state, null, 2));

  await page.screenshot({ path: '/tmp/jc-after-apply.png', fullPage: false });
  console.log('Screenshot saved');

  await browser.close();
})();
"
```

