arguments.task:
Read the job-copilot extension's chrome.storage to get the saved profile email (and other profile data), then fill the email field on the Oracle guest apply page.

Chrome is running on ws://localhost:9222.

Step 1 - Read storage:
```bash
cd /Users/shivam94/job-copilot && node -e "
const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.connectOverCDP('http://localhost:9222');
  const context = browser.contexts()[0];
  const pages = context.pages();
  const page = pages.find(p => p.url().includes('oraclecloud')) || pages[pages.length-1];

  // Access chrome.storage through the extension's service worker or content script
  // Method: inject a script that reads from chrome.storage via the background page
  const storageData = await page.evaluate(() => {
    // This runs in page context - can't directly access chrome.storage
    // But we can try accessing the extension's API
    return new Promise((resolve) => {
      try {
        // Check if chrome.runtime is accessible
        if (typeof chrome !== 'undefined' && chrome.runtime && chrome.runtime.id) {
          resolve({ chromeExtAvailable: true, id: chrome.runtime.id });
        } else {
          resolve({ chromeExtAvailable: false });
        }
      } catch(e) {
        resolve({ chromeExtAvailable: false, error: e.message });
      }
    });
  });
  console.log('Storage check:', JSON.stringify(storageData));

  // Alternative: read via CDP directly into the extension's background page
  // Let's try the extension's background page
  const targets = await context.pages();
  console.log('All pages:', targets.length);
  for (const t of targets) {
    const u = t.url();
    if (u.includes('chrome-extension://') || u.includes('chrome://')) {
      console.log('  Ext page:', u.substring(0, 100));
    }
  }

  await browser.close();
})();
"
```

If that doesn't work, try another approach - inject a content script or read storage via the extension's storage API directly by using the service worker:

```bash
cd /Users/shivam94/job-copilot && node -e "
const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.connectOverCDP('http://localhost:9222');
  const context = browser.contexts()[0];

  // Get all pages including extension pages
  const allTargets = await context.pages();
  console.log('All pages:');
  for (const t of allTargets) {
    console.log('  -', t.url().substring(0, 120));
  }

  // Try to find the background service worker
  // Chrome MV3 uses service workers, so it might not show as a page
  // Let's try via CDP sessions
  const cdpSession = await context.newCDPSession(allTargets[0] || await context.newPage());
  // Actually, let's just try chrome.storage via the Oracle page itself
  // The extension's content script IS running there

  const page = allTargets.find(p => p.url().includes('oraclecloud')) || allTargets[allTargets.length-1];

  // Try to read storage by messaging the extension
  // We need the extension ID - let's find it from manifest
  console.log('Reading manifest...');

  await browser.close();
})();
"
```

Then the simplest approach - just read the manifest.json to get the extension ID, then use CDP to evaluate in the extension context:

```bash
cd /Users/shivam94/job-copilot && node -e "
const fs = require('fs');
const path = require('path');
const manifest = JSON.parse(fs.readFileSync('extension/manifest.json', 'utf8'));
console.log('Extension ID from manifest:', 'not available - need to compute from key');
console.log('Manifest key:', manifest.key ? manifest.key.substring(0, 30) + '...' : '(none)');
"
```

Actually the simplest approach: the extension content script is already injected on the Oracle page. The content script communicates via window events or chrome.runtime. Let me just try to read the email from the Oracle page's DOM (the extension might have already filled it or stored it as data attributes). Or I can just check if the extension's `__jcFilling` or similar data is present.

Actually, the cleanest approach is to just use the extension's own test scripts which know how to talk to it:

```bash
cd /Users/shivam94/job-copilot && node -e "
// Try using the extension's service worker message API
// The extension has handlers for getAllFields, fillPersonal, etc.
// Let's check what section 'email' maps to

const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.connectOverCDP('http://localhost:9222');
  const context = browser.contexts()[0];
  const pages = context.pages();
  const page = pages.find(p => p.url().includes('oraclecloud')) || pages[pages.length-1];

  // The JC extension injects data on the page
  const jcData = await page.evaluate(() => {
    return {
      hasJcPanel: !!document.querySelector('.jc-panel'),
      hasFButtons: !!document.querySelector('.jc-fill-btn'),
      fillingState: document.documentElement.dataset.jcFilling,
    };
  });
  console.log('JC extension data:', JSON.stringify(jcData));

  // Read the email field on the page
  const emailField = await page.evaluate(() => {
    const input = document.querySelector('input[type=\"email\"]');
    if (!input) {
      // Try other selectors
      const allInputs = document.querySelectorAll('input');
      for (const inp of allInputs) {
        console.log('Input:', inp.id, inp.name, inp.type, inp.placeholder);
      }
      return null;
    }
    return {
      id: input.id,
      name: input.name,
      placeholder: input.placeholder,
      value: input.value,
    };
  });
  console.log('Email field:', JSON.stringify(emailField));

  await browser.close();
})();
"
```

Report: the email field details and any JC extension data visible on the page. If we can find the email field, we can fill it (using the F button or directly). But we need the actual email value - ask the user or try reading from chrome.storage via the extension background page.

