Create file: `/Users/shivam94/job-copilot/scripts/test/fill-verify-cycle.mjs`

This script should:

1. **Connect to Chrome** via Playwright CDP
2. **PRE-FILL LAYOUT SCAN** — scan all visible form fields with their current values + labels
3. **Read profile from chrome.storage** — connect to extension service worker, read `chrome.storage.sync` for profile data (email, name, phone, etc.)
4. **Read expected values** from `profile_full` or `resume_full_data` if available
5. **For each field, try to fill** using the extension's F button if available, or via paste events
6. **POST-FILL LAYOUT SCAN** — scan all fields again
7. **COMPARE** — for each field, show expected vs actual, mark pass/fail
8. **REPORT** — structured output with per-field results

```js
#!/usr/bin/env node
import { chromium } from 'playwright';

const CDP_URL = 'http://localhost:9222';

async function main() {
  const browser = await chromium.connectOverCDP(CDP_URL);
  const context = browser.contexts()[0];

  // Find Oracle page
  const pages = context.pages();
  const oraclePage = pages.find(p => p.url().includes('oraclecloud'));
  if (!oraclePage) {
    console.log('ERROR: No Oracle page found');
    await browser.close();
    return;
  }

  console.log('=== PRE-FILL LAYOUT SCAN ===');
  console.log('URL:', oraclePage.url());

  // Scan all form fields
  const preFields = await oraclePage.evaluate(() => {
    const fields = [];
    document.querySelectorAll('input:not([type=hidden]), select, textarea, [role=combobox]').forEach(el => {
      const rect = el.getBoundingClientRect();
      if (rect.width === 0 || rect.height === 0) return;

      // Find label
      let label = '';
      const labelEl = el.closest('label') || 
        (el.id && document.querySelector(`label[for="${el.id}"]`)) ||
        (el.parentElement?.querySelector('label'));
      if (labelEl) label = labelEl.textContent?.trim() || '';

      // Try to get aria-label, placeholder, name, id
      label = label || el.getAttribute('aria-label') || el.placeholder || el.name || el.id || '';

      // For comboboxes, value might be in toggle button text
      let value = el.value || '';
      const toggleId = el.id ? `${el.id}-toggle-button` : null;
      if (toggleId) {
        const toggle = document.getElementById(toggleId);
        if (toggle) {
          const labelSpan = toggle.querySelector('.cx-select__label-text');
          if (labelSpan) value = labelSpan.textContent?.trim() || value;
        }
      }

      fields.push({
        id: el.id,
        name: el.name,
        type: el.getAttribute('role') || el.type || el.tagName,
        label: label,
        value: value,
        placeholder: el.placeholder,
        tagName: el.tagName,
      });
    });
    return fields;
  });

  console.log(JSON.stringify(preFields, null, 2));

  // Find extension service worker
  const workers = context.serviceWorkers();
  console.log('\nService workers:', workers.length);
  let sw = null;
  for (const w of workers) {
    const url = w.url();
    console.log('SW:', url.substring(0, 120));
    if (url.includes('chrome-extension://')) {
      sw = w;
    }
  }

  // If no SW found via Playwright, try CDP approach
  if (!sw) {
    console.log('Trying CDP to find SW...');
    const cdpSession = await context.newCDPSession(oraclePage);
    const targets = await cdpSession.send('Target.getTargets');
    for (const t of targets.targetInfos) {
      console.log('Target:', t.type, t.title?.substring(0, 60), t.url?.substring(0, 60));
      if (t.type === 'service_worker' && t.url?.includes('chrome-extension://')) {
        // Connect to it
        const swSession = await cdpSession.send('Target.attachToTarget', {
          targetId: t.targetId,
          flatten: true,
        });
        console.log('Attached to SW:', t.targetId);
        // Try evaluate via this session
        // (this is a simplified approach - real implementation would use Runtime.evaluate)
      }
    }
  }

  // Read storage via page evaluate (the content script has access)
  // Actually, content scripts can use chrome.storage
  const storageData = await oraclePage.evaluate(() => {
    return new Promise((resolve) => {
      try {
        // Try to use the chrome.storage API - content scripts have access
        if (typeof chrome !== 'undefined' && chrome.storage) {
          chrome.storage.sync.get(null, (data) => {
            resolve({
              success: true,
              data: {
                profile_name: data.profile_name,
                profile_email: data.profile_email,
                profile_phone: data.profile_phone,
                // Don't include everything, just profile keys
                _keys: Object.keys(data || {}).filter(k => k.startsWith('profile_') || k.startsWith('llm_')),
              }
            });
          });
        } else {
          resolve({ success: false, error: 'chrome.storage not accessible' });
        }
      } catch(e) {
        resolve({ success: false, error: e.message });
      }
    });
  });

  console.log('\n=== STORAGE ===');
  console.log(JSON.stringify(storageData, null, 2));

  // If storage not accessible from page context, try another way
  // The extension injects __jcFilling on documentElement - check what data is available
  const pageData = await oraclePage.evaluate(() => {
    return {
      jcFilling: document.documentElement.dataset.jcFilling,
      hasFButtons: document.querySelectorAll('.jc-fill-btn').length,
      hasPanel: !!document.querySelector('.jc-panel'),
      panelHTML: document.querySelector('.jc-panel')?.innerHTML?.substring(0, 500),
    };
  });

  console.log('\n=== PAGE STATE ===');
  console.log(JSON.stringify(pageData, null, 2));

  // Now fill the email using proper paste events
  // The extension's fillText function handles Knockout correctly
  // Let's replicate its approach

  // Find the email field
  const emailField = preFields.find(f => f.type === 'email' || f.name?.includes('email') || f.id?.includes('email'));
  if (emailField) {
    console.log('\n=== FILLING EMAIL ===');

    // Try using the extension's F button first
    const fBtnResult = await oraclePage.evaluate((fieldId) => {
      // Find F button for this field
      const field = document.getElementById(fieldId);
      if (!field) return { ok: false, error: 'field not found' };

      // F buttons are positioned near the field
      const fBtn = field.parentElement?.querySelector('.jc-fill-btn');
      if (fBtn) {
        fBtn.click();
        return { ok: true, method: 'F-button' };
      }

      // Try using the extension's fill function directly
      if (window.__jcFillField) {
        window.__jcFillField(fieldId, profile_email || 'shivam.bhalla07@gmail.com');
        return { ok: true, method: '__jcFillField' };
      }

      return { ok: false, error: 'no F button or fill function' };
    }, emailField.id);

    console.log('F button result:', JSON.stringify(fBtnResult));

    if (!fBtnResult.ok) {
      // Fallback: direct paste events (what extension does internally)
      await oraclePage.evaluate(() => {
        const email = document.getElementById('primary-email-0');
        if (!email) return;

        // Clear first
        email.value = '';

        // Dispatch paste event
        email.value = 'shivam.bhalla07@gmail.com';
        email.dispatchEvent(new InputEvent('input', { inputType: 'insertFromPaste', bubbles: true }));
        email.dispatchEvent(new Event('change', { bubbles: true }));
        email.dispatchEvent(new Event('blur', { bubbles: true }));
      });
    }

    // Wait for Knockout to process
    await oraclePage.waitForTimeout(1000);

    // Verify
    const verifyResult = await oraclePage.evaluate(() => {
      const el = document.getElementById('primary-email-0');
      return {
        value: el?.value,
        classes: el?.className,
        // Check if Knockout updated
        koValue: el?.getAttribute('value'),
      };
    });
    console.log('Verify after fill:', JSON.stringify(verifyResult));

    // Check checkbox
    await oraclePage.evaluate(() => {
      const cb = document.getElementById('legal-disclaimer-checkbox');
      if (cb && !cb.checked) {
        cb.checked = true;
        cb.dispatchEvent(new Event('change', { bubbles: true }));
        cb.dispatchEvent(new Event('click', { bubbles: true }));
      }
    });

    // Try clicking Next properly
    console.log('\n=== CLICKING NEXT ===');

    // Find the Next button - use Oracle's data-binding
    await oraclePage.evaluate(() => {
      const form = document.querySelector('[data-bind*=\"submit: next\"] form') || 
                   document.querySelector('form');
      if (form) {
        // Try submitting the form directly (Knockout will catch the submit event)
        form.dispatchEvent(new Event('submit', { bubbles: true, cancelable: true }));
        return { method: 'form.submit' };
      }

      // Fallback: find Next button
      const nextBtn = Array.from(document.querySelectorAll('button')).find(b => 
        b.textContent?.trim() === 'Next' || b.textContent?.trim() === 'next'
      );
      if (nextBtn) {
        nextBtn.click();
        return { method: 'button.click' };
      }

      return { method: 'none', error: 'no form or Next button' };
    });

    // Wait for navigation
    await oraclePage.waitForTimeout(3000);

    console.log('URL after Next:', oraclePage.url());
    console.log('Title after Next:', await oraclePage.title());

    // POST-FILL LAYOUT SCAN
    console.log('\n=== POST-FILL LAYOUT SCAN ===');
    const postFields = await oraclePage.evaluate(() => {
      const fields = [];
      document.querySelectorAll('input:not([type=hidden]), select, textarea, [role=combobox]').forEach(el => {
        const rect = el.getBoundingClientRect();
        if (rect.width === 0 || rect.height === 0) return;

        let label = '';
        const labelEl = el.closest('label') || 
          (el.id && document.querySelector(`label[for=\"${el.id}\"]`)) ||
          (el.parentElement?.querySelector('label'));
        if (labelEl) label = labelEl.textContent?.trim() || '';
        label = label || el.getAttribute('aria-label') || el.placeholder || el.name || el.id || '';

        let value = el.value || '';
        const toggleId = el.id ? `${el.id}-toggle-button` : null;
        if (toggleId) {
          const toggle = document.getElementById(toggleId);
          if (toggle) {
            const labelSpan = toggle.querySelector('.cx-select__label-text');
            if (labelSpan) value = labelSpan.textContent?.trim() || value;
          }
        }

        fields.push({
          id: el.id,
          name: el.name,
          type: el.getAttribute('role') || el.type || el.tagName,
          label: label,
          value: value,
        });
      });
      return fields;
    });

    console.log(JSON.stringify(postFields, null, 2));

    // Take screenshot
    await oraclePage.screenshot({ path: '/tmp/jc-after-next.png', fullPage: true });
  }

  await browser.close();
}

main().catch(console.error);
