Fix the phone number fill for the Oracle application page and verify.

Chrome is running on ws://localhost:9222. Oracle page at `/apply/section/1`.

**The problem:** 
- Country code combobox (id=`country-codes-dropdownphoneNumber`): stays at `+33` when it should get country code from profile
- Phone number tel input (no id, type=tel): stays empty because Knockout's `formatPhoneNumber` binding + `onChangeNumber` handler reject paste events

**Profile phone:** `+33-753788537` → country_code=`+33`, phone=`753788537`

**Step 1: Diagnose the live fill behavior**

```bash
cd /Users/shivam94/job-copilot && node -e "
const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.connectOverCDP('http://localhost:9222');
  const context = browser.contexts()[0];
  const pages = context.pages();
  const page = pages.find(p => p.url().includes('oraclecloud')) || pages[pages.length-1];

  // Try clicking the F button for the phone number input (no id, so find by selector)
  // First let's find the actual phone input element
  const phoneInput = await page.evaluate(() => {
    const tel = document.querySelector('input[type=tel]');
    if (!tel) return null;
    return {
      id: tel.id,
      name: tel.name,
      rect: tel.getBoundingClientRect(),
      ariaLabel: tel.getAttribute('aria-label'),
      parentClass: tel.parentElement?.className,
    };
  });
  console.log('Phone tel input:', JSON.stringify(phoneInput, null, 2));

  // Try filling with different event strategies
  if (phoneInput) {
    // Strategy 1: Click F button if it exists
    const hasF = await page.evaluate(() => {
      const tel = document.querySelector('input[type=tel]');
      if (!tel) return false;
      const fBtn = tel.parentElement?.querySelector('.jc-field-fill-btn');
      return !!fBtn;
    });
    console.log('Has F button:', hasF);

    // Let's try filling the tel input with different approaches
    console.log('\\n=== Trying char-by-char approach ===');

    // Clear first
    await page.evaluate(() => {
      const tel = document.querySelector('input[type=tel]');
      if (tel) {
        tel.value = '';
        tel.dispatchEvent(new Event('input', { bubbles: true }));
      }
    });

    // Char by char with key events
    const phoneDigits = '753788537';
    for (const char of phoneDigits) {
      await page.evaluate((c) => {
        const tel = document.querySelector('input[type=tel]');
        if (!tel) return;
        tel.value += c;
        tel.dispatchEvent(new KeyboardEvent('keydown', { key: c, bubbles: true }));
        tel.dispatchEvent(new Event('input', { bubbles: true }));
        tel.dispatchEvent(new KeyboardEvent('keyup', { key: c, bubbles: true }));
      }, char);
      await page.waitForTimeout(100);
    }

    // Wait for Knockout to process
    await page.waitForTimeout(1000);

    const verify = await page.evaluate(() => {
      const tel = document.querySelector('input[type=tel]');
      return {
        value: tel?.value,
      };
    });
    console.log('After char-by-char:', JSON.stringify(verify));
  }

  await browser.close();
})();
"
