    const val = await page.evaluate((fieldId) => {
      const el = document.getElementById(fieldId);
      if (!el) return { error: 'not found' };
      let value = el.value || '';
      const toggleId = el.id ? el.id + '-toggle-button' : null;
      if (toggleId && document.getElementById(toggleId)) {
        const ls = document.getElementById(toggleId).querySelector('.cx-select__label-text');
        if (ls) value = ls.textContent?.trim() || value;
      }
      return { value: value.substring(0, 40) };
    }, field.id);

    console.log('  Value after F-click:', val.value || '(empty)');

    // Now clear this field for next test
    await page.evaluate((fieldId) => {
      const el = document.getElementById(fieldId);
      if (!el) return;
      el.value = '';
      el.dispatchEvent(new Event('input', { bubbles: true }));
      el.dispatchEvent(new Event('change', { bubbles: true }));
    }, field.id);
    await page.waitForTimeout(300);
  }

  await browser.close();
})();
