Read ALL chrome.storage.sync data from the job-copilot extension to see exactly what profile fields are stored.

Chrome is running on ws://localhost:9222 with extension ID `nbpeoddibjhngmomojgpeoiceocnoknn`.

Run this CDP script to read storage via the extension's service worker:
```bash
cd /Users/shivam94/job-copilot && node -e "
const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.connectOverCDP('http://localhost:9222');
  const context = browser.contexts()[0];

  // Find the extension service worker
  const workers = context.serviceWorkers();
  let swSession = null;
  for (const w of workers) {
    const url = w.url();
    if (url.includes('chrome-extension://')) {
      swSession = w;
      console.log('Found SW:', url.substring(0, 120));
      break;
    }
  }

  if (!swSession) {
    console.log('No SW found via Playwright, trying CDP method...');
    const pages = context.pages();
    const page = pages[0] || await context.newPage();
    const cdp = await context.newCDPSession(page);

    // List targets to find SW
    const { targetInfos } = await cdp.send('Target.getTargets');
    for (const t of targetInfos) {
      if (t.type === 'service_worker' && t.url?.includes('nbpeoddibjhngmomojgpeoiceocnoknn')) {
        console.log('Found SW target:', t.targetId);
        // Attach to it
        const swCdp = await cdp.send('Target.attachToTarget', {
          targetId: t.targetId,
          flatten: true
        });
        console.log('Attached');
      }
    }
  }

  // Read storage via the Oracle page's content script (which has chrome.storage access)
  const pages = context.pages();
  const page = pages.find(p => p.url().includes('oraclecloud')) || pages[pages.length-1];

  // The extension content script has chrome.storage access
  const storage = await page.evaluate(() => {
    return new Promise((resolve) => {
      try {
        if (typeof chrome !== 'undefined' && chrome.storage && chrome.storage.sync) {
          chrome.storage.sync.get(null, (data) => {
            // Return all profile_* keys and resume data summary
            const result = {};
            for (const [k, v] of Object.entries(data || {})) {
              if (k.startsWith('profile_') || k.startsWith('resume_') || k === 'learned_fields' || k === 'saved_answers') {
                if (typeof v === 'string' && v.length > 100) {
                  result[k] = v.substring(0, 100) + '...';
                } else {
                  result[k] = v;
                }
              }
            }
            resolve(result);
          });
        } else {
          resolve({ error: 'chrome.storage not accessible from page context' });
        }
      } catch(e) {
        resolve({ error: e.message });
      }
    });
  });

  console.log('\\n=== STORAGE DATA ===');
  console.log(JSON.stringify(storage, null, 2));

  // Also check if learned_fields has expected values for address/street
  if (storage.learned_fields) {
    const learnedFields = await page.evaluate(() => {
      return new Promise((resolve) => {
        chrome.storage.sync.get('learned_fields', (data) => {
          resolve(data.learned_fields || {});
        });
      });
    });
    console.log('\\n=== LEARNED FIELDS ===');
    console.log(JSON.stringify(learnedFields, null, 2));
  }

  await browser.close();
})();
"
