Chrome running on ws://localhost:9222.

Step 1 - Click Add Experience with proper PointerEvent sequence (Oracle React):

```bash
cd /Users/shivam94/job-copilot && node -e "
const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.connectOverCDP('http://localhost:9222');
  const context = browser.contexts()[0];
  const pages = context.pages();
  const page = pages.find(p => p.url().includes('oraclecloud')) || pages[pages.length-1];

  // Click Add Experience with PointerEvent sequence
  await page.evaluate(() => {
    const btn = Array.from(document.querySelectorAll('button')).find(b => b.textContent?.trim() === 'Add Experience');
    if (!btn) return console.log('Button not found');

    btn.scrollIntoView({block:'center'});
    setTimeout(() => {
      const rect = btn.getBoundingClientRect();
      const x = rect.x + rect.width/2;
      const y = rect.y + rect.height/2;

      btn.dispatchEvent(new PointerEvent('pointerdown', { bubbles: true, clientX: x, clientY: y }));
      btn.dispatchEvent(new MouseEvent('mousedown', { bubbles: true, clientX: x, clientY: y }));
      btn.dispatchEvent(new PointerEvent('pointerup', { bubbles: true, clientX: x, clientY: y }));
      btn.dispatchEvent(new MouseEvent('mouseup', { bubbles: true, clientX: x, clientY: y }));
      btn.dispatchEvent(new MouseEvent('click', { bubbles: true, clientX: x, clientY: y }));
    }, 300);
  });

  await page.waitForTimeout(3000);

  console.log('URL:', page.url());
  console.log('Title:', await page.title());

  // Capture ALL visible fields after Add Experience opens
  const fields = await page.evaluate(() => {
    const f = [];
    document.querySelectorAll('input:not([type=hidden]):not([type=file]), select, textarea, [role=combobox]').forEach(el => {
      const r = el.getBoundingClientRect();
      if (r.width === 0 || r.height === 0) return;

      let label = el.getAttribute('aria-label') || el.placeholder || el.name || el.id || '';
      const lab = el.closest('label') || (el.id && document.querySelector('label[for=\"' + el.id + '\"]'));
      if (lab) label = lab.textContent?.trim() || label;

      let value = el.value || '';
      const toggleId = el.id ? el.id + '-toggle-button' : null;
      if (toggleId && document.getElementById(toggleId)) {
        const ls = document.getElementById(toggleId).querySelector('.cx-select__label-text');
        if (ls) value = ls.textContent?.trim() || value;
      }

      const fBtn = el.parentElement?.querySelector('.jc-field-fill-btn');

      f.push({
        idx: f.length,
        id: (el.id || '(no id)').substring(0, 50),
        label: (label || '').substring(0, 60),
        value: (value || '').substring(0, 40),
        type: el.type || el.getAttribute('role') || el.tagName,
        hasFbtn: !!fBtn,
      });
    });
    return f;
  });

  console.log('\\n=== FIELDS AFTER ADD EXPERIENCE ===');
  console.log(JSON.stringify(fields, null, 2));

  await page.screenshot({ path: '/tmp/jc-experience-form.png', fullPage: true });
  console.log('\\nScreenshot saved');

  await browser.close();
})();
"
