const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.connectOverCDP('http://localhost:9222');
  const context = browser.contexts()[0];
  const pages = context.pages();
  const page = pages.find(p => p.url().includes('oraclecloud')) || pages[pages.length-1];

  // Get all fields with F buttons
  const fieldsWithF = await page.evaluate(() => {
    const f = [];
    document.querySelectorAll('input:not([type=hidden]):not([type=file]), select, textarea, [role=combobox]').forEach(el => {
      const r = el.getBoundingClientRect();
      if (r.width === 0 || r.height === 0) return;

      let label = el.getAttribute('aria-label') || el.placeholder || el.name || el.id || '';
      const lab = el.closest('label') || (el.id && document.querySelector('label[for=\"' + el.id + '\"]'));
      if (lab) label = lab.textContent?.trim() || label;

      let value = el.value || '';
      const tid = el.id ? el.id + '-toggle-button' : null;
      if (tid && document.getElementById(tid)) {
        const ls = document.getElementById(tid).querySelector('.cx-select__label-text');
        if (ls) value = ls.textContent?.trim() || value;
      }

      const fBtn = el.parentElement?.querySelector('.jc-field-fill-btn');
      const fBtnRect = fBtn?.getBoundingClientRect();

      if (fBtn) {
        f.push({
          idx: f.length,
          id: (el.id || '(no id)').substring(0, 50),
          label: (label || '').substring(0, 50),
          value: (value || '').substring(0, 30),
          type: el.type || el.getAttribute('role') || el.tagName,
          btnVisible: fBtnRect ? fBtnRect.width > 0 : false,
          btnY: fBtnRect ? fBtnRect.y : -1,
        });
      }
    });
    return f;
  });

  console.log('Fields with F buttons:', fieldsWithF.length);

  // Clear all first
  await page.evaluate(() => {
    const floatBtn = document.getElementById('jc-float-btn');
    if (floatBtn) floatBtn.click();
  });
  await page.waitForTimeout(500);

  await page.evaluate(() => {
    const clearBtn = document.getElementById('jc-clear-form');
    if (clearBtn) clearBtn.click();
  });
  await page.waitForTimeout(300);
  await page.evaluate(() => {
    const clearBtn = document.getElementById('jc-clear-form');
    if (clearBtn) clearBtn.click();
  });
  await page.waitForTimeout(1500);

  // Close panel
  await page.evaluate(() => {
    const floatBtn = document.getElementById('jc-float-btn');
    if (floatBtn) floatBtn.click();
  });
  await page.waitForTimeout(500);

  console.log('\\n=== TESTING EACH FIELD ===');
  console.log('');

  let passed = 0;
  let failed = 0;

  for (const field of fieldsWithF) {
    const label = field.label;
    const fid = field.id;

    // Scroll to field
    await page.evaluate((id) => {
      const el = document.getElementById(id);
      if (el) el.scrollIntoView({ block: 'center' });
    }, fid);
    await page.waitForTimeout(400);

    // Click F button
    const coords = await page.evaluate((id) => {
      const el = document.getElementById(id);
      if (!el) return null;
      const btn = el.parentElement?.querySelector('.jc-field-fill-btn');
      if (!btn) return null;
      const r = btn.getBoundingClientRect();
      return { x: r.x + r.width/2, y: r.y + r.height/2 };
    }, fid);

    if (!coords) {
      console.log('  FAIL ' + label + ' - no F button coords');
      failed++;
      continue;
    }

    await page.mouse.click(coords.x, coords.y);
    await page.waitForTimeout(1000);

    // Read value
    const result = await page.evaluate((id) => {
      const el = document.getElementById(id);
      if (!el) return { error: 'not found' };
      let v = el.value || '';
      const tid = el.id ? el.id + '-toggle-button' : null;
      if (tid && document.getElementById(tid)) {
        const ls = document.getElementById(tid).querySelector('.cx-select__label-text');
        if (ls) v = ls.textContent?.trim() || v;
      }
      return { value: v.substring(0, 40) };
    }, fid);

    const status = result.value && result.value !== '' ? 'PASS' : 'FAIL';
    console.log('  ' + status + ' ' + label + ' -> ' + (result.value || '(empty)'));
    if (status === 'PASS') passed++;
    else failed++;

    // Clear field
    await page.evaluate((id) => {
      const el = document.getElementById(id);
      if (!el) return;
      el.value = '';
      el.dispatchEvent(new Event('input', { bubbles: true }));
    }, fid);
    await page.waitForTimeout(200);
  }

  console.log('');
  console.log('=== SUMMARY: ' + passed + ' passed, ' + failed + ' failed, ' + (passed+failed) + ' total ===');

  await browser.close();
})();
"
