      setTimeout(() => {
        const r = btn.getBoundingClientRect();
        ['pointerdown','mousedown','pointerup','mouseup','click'].forEach(evt => {
          btn.dispatchEvent(new PointerEvent(evt, {bubbles:true, clientX: r.x+r.width/2, clientY: r.y+r.height/2}));
        });
      }, 200);
      return true;
    }
    return false;
  });
  console.log('Add Experience clicked:', hasAddBtn);
  await page.waitForTimeout(3000);

  // Get all fields with F buttons
  const fields = await page.evaluate(() => {
    const f = [];
    document.querySelectorAll('input:not([type=hidden]):not([type=file]), select, textarea, [role=combobox]').forEach(el => {
      const r = el.getBoundingClientRect();
      if (r.width === 0 || r.height === 0) return;
      let label = el.getAttribute('aria-label') || el.placeholder || el.name || el.id || '';
      const lab = el.closest('label') || (el.id && document.querySelector('label[for=\"' + el.id + '\"]'));
      if (lab) label = lab.textContent?.trim() || label;
      const fBtn = el.parentElement?.querySelector('.jc-field-fill-btn');
      f.push({
        id: (el.id || '').substring(0, 50),
        label: (label || '').substring(0, 55),
        type: el.type || el.getAttribute('role') || el.tagName,
        hasFbtn: !!fBtn,
      });
    });
    return f;
  });

  const withF = fields.filter(f => f.hasFbtn);
  const withoutF = fields.filter(f => !f.hasFbtn);

  console.log('\\nFields with F buttons: ' + withF.length);
  console.log('Fields WITHOUT F buttons: ' + withoutF.length);
  withoutF.forEach(f => console.log('  [ ] ' + f.label + ' (' + f.id + ')'));

  console.log('\\n=== TESTING F BUTTONS ===');

  for (const field of withF) {
    await page.evaluate((id) => {
      const el = document.getElementById(id);
      if (el) el.scrollIntoView({block:'center'});
    }, field.id);
    await page.waitForTimeout(200);

    const coord = await page.evaluate((id) => {
      const el = document.getElementById(id);
      if (!el) return null;
      const btn = el.parentElement?.querySelector('.jc-field-fill-btn');
      if (!btn) return null;
      const r = btn.getBoundingClientRect();
      return { x: r.x + r.width/2, y: r.y + r.height/2 };
    }, field.id);

    if (!coord) { console.log('  SKIP ' + field.label); continue; }

    await page.mouse.click(coord.x, coord.y);
    await page.waitForTimeout(1000);

    const val = await page.evaluate((id) => {
      const el = document.getElementById(id);
      if (!el) return '';
      let v = el.value || '';
      const tid = el.id ? el.id + '-toggle-button' : null;
      if (tid && document.getElementById(tid)) {
        const ls = document.getElementById(tid).querySelector('.cx-select__label-text');
        if (ls) v = ls.textContent?.trim() || v;
      }
      return (v || '').substring(0, 50);
    }, field.id);

    console.log('  ' + (val ? 'OK' : 'EMPTY') + ' ' + field.label + ' = \"' + (val || '') + '\"');
  }

  await browser.close();
})();
